+#define sEOF "-EOF"             /* '-' as in PEM and MIME boundaries */
+#define junk "#foo"             /* Skipped initial content */
+
+#define EOF_RETURN (-1729)      /* Distinct from -1, etc., internal results */
+#define NLEN 6
+#define NVAR 5
