+/* Append one base64 codepoint, adding newlines after every `llen` bytes */
+static int memout(BIO *mem, char c, int llen, int *pos)
+{
+    if (BIO_write(mem, &c, 1) != 1)
+        return 0;
+    if (++*pos == llen) {
+        *pos = 0;
+        c = '\n';
+        if (BIO_write(mem, &c, 1) != 1)
+            return 0;
+    }
+    return 1;
