[][292] +     */
[][293] +    if (t->trunc > 0
[][294] +        || ((t->bytes > 0 || t->no_nl) && *t->suffix && *t->suffix != '-')
[][295] +        || (t->no_nl && *t->prefix)) {
[][296] +        if ((ret = ret < 0 ? 0 : -1) != 0)
