[][313] +static int generic_case(test_case *t, int verbose)
[][314] +{
[][315] +    unsigned *llen;
[][316] +    unsigned *wscnt;
[][317] +    int ok = 1;
[][318] +
[][319] +    for (llen = linelengths; *llen > 0; ++llen) {
[][320] +        for (wscnt = wscnts; *wscnt >= 0 && *wscnt * 2 < *llen; ++wscnt) {
[][321] +            int extra = t->no_nl ? 64 : 0;
[][322] +
[][323] +            /*
[][324] +             * Use a longer line for NO_NL tests, in particular, eventually
[][325] +             * exceeding 1k bytes.
[][326] +             */
[][327] +            if (test_bio_base64_run(t, *llen + extra, *wscnt) != 0)
[][328] +                ok = 0;
[][329] +
[][330] +            if (verbose) {
[][331] +                fprintf(stderr, "bio_base64_test: ok=%d", ok);
[][332] +                if (*t->prefix)
[][333] +                    fprintf(stderr, ", prefix='%s'", t->prefix);
[][334] +                if (t->encoded)
[][335] +                    fprintf(stderr, ", data='%s'", t->encoded);
[][336] +                else
[][337] +                    fprintf(stderr, ", datalen=%u", t->bytes);
[][338] +                if (t->trunc)
[][339] +                    fprintf(stderr, ", trunc=%d", t->trunc);
[][340] +                if (*t->suffix)
[][341] +                    fprintf(stderr, ", suffix='%s'", t->suffix);
[][342] +                fprintf(stderr, ", linelen=%u", *llen);
[][343] +                fprintf(stderr, ", wscount=%u", *wscnt);
[][344] +                if (t->retry)
[][345] +                    fprintf(stderr, ", retriable");
[][346] +                if (t->no_nl)
[][347] +                    fprintf(stderr, ", oneline");
[][348] +                fputc('\n', stderr);
[][349] +            }
[][350] +
[][351] +            /* For verbatim input no effect from varying llen or wscnt */
[][352] +            if (t->encoded)
[][353] +                return ok;
[][354] +        }
[][355] +        /*
[][356] +         * Longer 'llen' has no effect once we're sure to not have multiple
[][357] +         * lines of data
[][358] +         */
[][359] +        if (*llen > t->bytes + (t->bytes >> 1))
[][360] +            break;
[][361] +    }
[][362] +    return ok;
[][363] +}
