[][371] +static int test_bio_base64_generated(int idx)
[][372] +{
[][373] +    test_case t;
[][374] +    int variant;
[][375] +    int lencase;
[][376] +    int padcase;
[][377] +    int q = idx;
[][378] +
[][379] +    lencase = quotrem(q, NLEN, &q);
[][380] +    variant = quotrem(q, NVARPAD, &q);
[][381] +    padcase = quotrem(variant, NPAD, &variant);
[][382] +    t.retry = quotrem(q, 2, &q);
[][383] +    t.no_nl = quotrem(q, 2, &q);
[][384] +
[][385] +    if (q != 0) {
[][386] +        fprintf(stderr, "Test index out of range: %d", idx);
[][387] +        return 0;
[][388] +    }
[][389] +
[][390] +    t.prefix = prefixes[variant];
[][391] +    t.encoded = NULL;
[][392] +    t.bytes  = lengths[lencase];
[][393] +    t.trunc = 0;
[][394] +    if (padcase && padcase < 3)
[][395] +        t.bytes  += padcase;
[][396] +    else if (padcase >= 3)
[][397] +        t.trunc = padcase - 2;
[][398] +    t.suffix = suffixes[variant];
[][399] +
[][400] +    if (padcase != 0 && (*t.suffix && *t.suffix != '-')) {
[][401] +        TEST_error("Unexpected suffix test after padding");
[][402] +        return 0;
[][403] +    }
[][404] +
[][405] +    return generic_case(&t, 0);
[][406] +}
