[][408] +static int test_bio_base64_corner_case_bug(int idx)
[][409] +{
[][410] +    test_case t;
[][411] +    int q = idx;
[][412] +
[][413] +    t.retry = quotrem(q, 2, &q);
[][414] +    t.no_nl = quotrem(q, 2, &q);
[][415] +
[][416] +    if (q != 0) {
[][417] +        fprintf(stderr, "Test index out of range: %d", idx);
[][418] +        return 0;
[][419] +    }
[][420] +
[][421] +    /* 9 bytes of skipped non-base64 input + newline */
[][422] +    t.prefix = "#foo\n#bar";
[][423] +
[][424] +    /* 9 bytes on 2nd and subsequent lines */
[][425] +    t.encoded = "A\nAAA\nAAAA\n";
[][426] +    t.suffix = "";
[][427] +
[][428] +    /* Expected decode length */
[][429] +    t.bytes = 6;
[][430] +    t.trunc = 0;    /* ignored */
[][431] +
[][432] +    return generic_case(&t, 0);
