[][435] +int setup_tests(void)
[][436] +{
[][437] +    int numidx;
[][438] +
[][439] +    memset(gunk, 'o', sizeof(gunk));
[][440] +    gunk[0] = '#';
[][441] +    gunk[sizeof(gunk) - 1] = '\0';
[][442] +
[][443] +    /*
[][444] +     * Test 5 variants of prefix or suffix
[][445] +     *
[][446] +     *  - both empty
[][447] +     *  - short junk prefix
[][448] +     *  - long gunk prefix (> internal BIO 1k buffer size),
[][449] +     *  - soft EOF suffix
[][450] +     *  - junk suffix (expect to detect an error)
[][451] +     *
[][452] +     * For 6 input lengths of randomly generated raw input:
[][453] +     *
[][454] +     *  0, 3, 48, 192, 768 and 1536
[][455] +     *
[][456] +     * corresponding to encoded lengths (plus linebreaks and ignored
[][457] +     * whitespace) of:
[][458] +     *
[][459] +     *  0, 4, 64, 256, 1024 and 2048
[][460] +     *
[][461] +     * Followed by zero, one or two additional bytes that may involve padding,
[][462] +     * or else (truncation) 1, 2 or 3 bytes with missing padding.
[][463] +     * Only the the first four variants make sense with padding or truncated
[][464] +     * groups.
[][465] +     *
[][466] +     * With two types of underlying BIO
[][467] +     *
[][468] +     *  - Non-retriable underlying BIO
[][469] +     *  - Retriable underlying BIO
[][470] +     *
[][471] +     * And with/without the BIO_FLAGS_BASE64_NO_NL flag, where now an error is
[][472] +     * expected with the junk and gunk prefixes, however, but the "soft EOF"
[][473] +     * suffix is still accepted.
[][474] +     *
[][475] +     * Internally, each test may loop over a range of encoded line lengths and
[][476] +     * whitespace average "densities".
[][477] +     */
[][478] +    numidx = NLEN * (NVAR * NPAD - NPAD + 1) * 2 * 2;
[][479] +    ADD_ALL_TESTS(test_bio_base64_generated, numidx);
[][480] +
[][481] +    /*
[][482] +     * Corner case in original code that skips ignored input, when the ignored
[][483] +     * length is one byte longer than the total of the second and later lines
[][484] +     * of valid input in the first 1k bytes of input.  No content variants,
[][485] +     * just BIO retry status and oneline flags vary.
[][486] +     */
[][487] +    numidx = 2 * 2;
[][488] +    ADD_ALL_TESTS(test_bio_base64_corner_case_bug, numidx);
[][489] +
[][490] +    return 1;
[][491] +}
